  ('elementary-10ced7e2-moex-00244', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '公務人員不得為支持或反對特定之政黨、其他政治團體或公職候選人，在大眾傳播媒體具銜或具名廣告， 但下列何種情況例外？', '["公職候選人之配偶及二親等以內血親、姻親，不在此限", "公職候選人之配偶及二親等以內血親、姻親只具名不具銜者，不在此限", "公職候選人之配偶及二親等以內血親、姻親只具銜不具名者，不在此限", "公職候選人之配偶及三親等以內血親、姻親，不在此限"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "0d6660489e0e", "answer_pdf_sha1": "b09042515ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00245', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-21e891bc', 'sub-elementary-10ced7e2-01', NULL, 'single_choice', '各機關首長或主管人員應於何時起至投票日止，禁止政黨、公職候選人或其支持者進入辦公處所之造訪活動？', '["獲政黨或政治團體正式提名之日", "正式登記為候選人之日", "候選人抽籤決定號次之日", "候選人名單公告之日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "0d6660489e0e", "answer_pdf_sha1": "b09042515ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人事行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00246', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '假定甲國的生產可能曲線往右上方擴增，下列何者可能是甲國生產可能性曲線發生變化的原因？', '["貧富差距縮小", "經濟出現停滯", "失業率上升", "生產技術進步"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00247', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '經濟制度是指政府介入人民經濟生活的方式與程度，下列有關「市場經濟制度」的敘述，何者錯誤？', '["政府保障人民的消費自由", "政府尊重市場的價格機能", "政府讓個人依自利做決策", "政府將生產工具收歸國有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00248', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '某列車與一輛從斜坡上跌落到鐵軌上的工程車相撞後出軌，造成人員傷亡慘重。事故發生後，某位脫困乘 客因被其他人拍到站在事故旁的邊坡，而被媒體誤報為「偷偷施工又見死不救的工人」，導致該名乘客被 誤解的網路鄉民肉搜與圍剿。從媒體識讀的角度檢視，何者最適合用來描述前述媒體報導所引發的現象？', '["媒體未善盡查證責任，報導內容出現不實的訊息", "媒體為搶收視率，以煽情的內容渲染大眾的情緒", "媒體形塑勞工負面刻板印象，加劇民眾對勞工的歧視", "媒體報導檢察官尚在調查的訊息，違反偵查不公開原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00249', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '政府利用租稅課徵與財政支出的手段，可以發揮一定的經濟效果，下列有關政府財政收支的敘述，何者 正確？', '["降低進口關稅可保護本國就業機會，增加消費者福利", "提高營業稅與貨物稅稅率，可縮小社會財富分配差距", "降低土地增值稅稅率，助長土地投機不利租稅公平性", "擴大公共工程的投資性支出，會增加總體經濟的供給，可刺激經濟景氣的復甦"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL),
  ('elementary-10ced7e2-moex-00250', 'elementary-10ced7e2', 'elementary-10ced7e2-moex-113-b3f42868', 'sub-elementary-10ced7e2-02', NULL, 'single_choice', '某報報導：「疫情升溫，清境、日月潭及溪頭等地的旅館業表示，退房率大約一至二成，且訂房也沒像往 年熱絡，價格正往下修正……」其他條件不變下，試問前述報導最符合下列何種現象？', '["需求曲線不動，需求量（quantitydemanded）減少", "需求曲線不動，需求量（quantitydemanded）增加", "需求曲線左移，需求量（quantitydemanded）減少", "需求曲線左移，需求量（quantitydemanded）增加"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:44+00:00", "source_pdf_sha1": "4177c3d25909", "answer_pdf_sha1": "d775e2e2ff9d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "506", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "人事行政"}'::jsonb, NULL)
